import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class SketchBasedJoinEstimatorBackgroundRefreshTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void backgroundRefreshDoesNotRebuildEmptyStoreEveryTick() throws Exception {
		CountingEmptyStore store = new CountingEmptyStore();
		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(store,
				SketchBasedJoinEstimator.Config.defaults()
						.withNominalEntries(64)
						.withThrottleEveryN(1)
						.withThrottleMillis(0)
						.withRefreshSleepMillis(10));

		estimator.startBackgroundRefresh(0);
		try {
			Thread.sleep(120);

			assertTrue(store.rebuildCount() <= 1,
					"Empty stores should not rescan on every refresh tick");
		} finally {
			estimator.stop();
		}
	}

	@Test
	void backgroundRefreshLoadsPersistedSnapshotWithoutCallerReadyLazyLoad(@TempDir Path dataDir) throws Exception {
		CountingEmptyStore store = new CountingEmptyStore(VF.createStatement(VF.createIRI("urn:s"),
				VF.createIRI("urn:p"), VF.createIRI("urn:o")));
		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(store,
				SketchBasedJoinEstimator.Config.defaults()
						.withNominalEntries(64)
						.withThrottleEveryN(1)
						.withThrottleMillis(0)
						.withRefreshSleepMillis(10));
		estimator.configurePersistence(dataDir.resolve("join-estimator.rjes"), false);
		try {
			estimator.rebuild();
			assertTrue(estimator.isReadyNonBlocking());
			assertTrue(estimator.persistIfDirty());
			estimator.unload();

			assertFalse(estimator.isReadyNonBlocking(), "Nonblocking readiness should not load persisted sketches");
			assertEquals(1, store.rebuildCount());

			estimator.startBackgroundRefresh(3);

			assertTrue(estimator.awaitReady(5, TimeUnit.SECONDS),
					"Background refresh should load the persisted snapshot");
			assertEquals(1, store.rebuildCount(), "Background snapshot load should not rebuild the store");
		} finally {
			estimator.close();
		}
	}

	@Test
	void deferredBackgroundRebuildKeepsPublishedSnapshotReady() throws Exception {
		DeferringAfterInitialRebuildStore store = new DeferringAfterInitialRebuildStore(
				VF.createStatement(VF.createIRI("urn:s"), VF.createIRI("urn:p"), VF.createIRI("urn:o")));
		SketchBasedJoinEstimator estimator = new SketchBasedJoinEstimator(store,
				SketchBasedJoinEstimator.Config.defaults()
						.withNominalEntries(64)
						.withThrottleEveryN(1)
						.withThrottleMillis(0)
						.withRefreshSleepMillis(10));

		try {
			estimator.rebuild();
			assertTrue(estimator.isReadyNonBlocking(), "Initial rebuild should publish a ready snapshot");
			double before = estimator.estimateCount(SketchBasedJoinEstimator.Component.S, null, "urn:p", "urn:o",
					null);
			assertTrue(before > 0.0d, "Expected initial snapshot to estimate the loaded statement");

			estimator.startBackgroundRefresh(-1);
			assertTrue(store.awaitDeferredAttempt(),
					"Expected background refresh to attempt and defer a later rebuild");

			assertTrue(estimator.isReadyNonBlocking(),
					"Deferred background rebuild should not make the published snapshot unavailable");
			assertEquals(before,
					estimator.estimateCount(SketchBasedJoinEstimator.Component.S, null, "urn:p", "urn:o", null),
					0.0d);
		} finally {
			estimator.close();
		}
	}

	private static final class CountingEmptyStore implements SketchStatementSource {
		private final AtomicInteger rebuildCount = new AtomicInteger();
		private final List<Statement> statements;

		CountingEmptyStore(Statement... statements) {
			this.statements = List.of(statements);
		}

		int rebuildCount() {
			return rebuildCount.get();
		}

		@Override
		public ValueFactory getValueFactory() {
			return VF;
		}

		@Override
		public CloseableIteration<? extends Statement> getStatements(Resource subj, IRI pred, Value obj,
				Resource... contexts) {
			rebuildCount.incrementAndGet();
			return new CloseableIteratorIteration<>(statements.iterator());
		}
	}

	private static final class DeferringAfterInitialRebuildStore implements SketchStatementSource {
		private final AtomicInteger rebuildCount = new AtomicInteger();
		private final List<Statement> statements;

		DeferringAfterInitialRebuildStore(Statement... statements) {
			this.statements = List.of(statements);
		}

		boolean awaitDeferredAttempt() throws InterruptedException {
			long deadlineNanos = System.nanoTime() + TimeUnit.SECONDS.toNanos(5);
			while (System.nanoTime() - deadlineNanos < 0L) {
				if (rebuildCount.get() >= 2) {
					return true;
				}
				Thread.sleep(10);
			}
			return false;
		}

		@Override
		public ValueFactory getValueFactory() {
			return VF;
		}

		@Override
		public CloseableIteration<? extends Statement> getStatements(Resource subj, IRI pred, Value obj,
				Resource... contexts) {
			if (rebuildCount.incrementAndGet() > 1) {
				throw new SketchStatementSourceException(new IllegalStateException("deferred"));
			}
			return new CloseableIteratorIteration<>(statements.iterator());
		}
	}

	private static final class OomDuringRebuildEstimator extends SketchBasedJoinEstimator {
		private final AtomicInteger rebuildAttempts = new AtomicInteger();

		private OomDuringRebuildEstimator(SketchStatementSource sailStore, Config config) {
			super(sailStore, config);
		}

		int rebuildAttempts() {
			return rebuildAttempts.get();
		}

		@Override
		public synchronized long rebuild() {
			rebuildAttempts.incrementAndGet();
			throw new OutOfMemoryError("simulated");
		}
	}
}
